解释: 小牛有6种购买方案，所选蛋糕与所选礼物在数组中对应的下标分别是：
第1种方案: cake [0] + gift [0] = 10 + 5 = 15;
第2种方案: cake [0] + gift [1]= 10 + 5 = 15;
第3种方案: cake [0] + gift [2] = 10 + 2 = 12;
第4种方案: cake [2] + gift [0] = 5 + 5 = 10;
第5种方案: cake [2] + gift [1]= 5 + 5 = 10;
第6种方案: cake [2] + gift [2] = 5 + 2 = 7。

solutions.Python:
import re

# 输入获取
# 这里re.sub的原因是&#xff1a;有考友反馈实际考试存在20%的用例输入类似于 [10,20,5] 这种
cakes = list(map(int, re.sub(r"[\[\]]", "", input()).split(",")))
gifts = list(map(int, re.sub(r"[\[\]]", "", input()).split(",")))
x = int(input())


def searchLast(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) >> 1
        midVal = arr[mid]

        if midVal > target:
            high = mid - 1
        elif midVal < target:
            low = mid + 1
        else:
            if mid == len(arr) - 1 or arr[mid] != arr[mid + 1]:
                return mid
            else:
                low = mid + 1

    return -low - 1


# 算法入口
def getResult():
    cakes.sort()

    ans = 0
    for gift in gifts:
        if x <= gift:
            continue

        maxCake = x - gift
        i = searchLast(cakes, maxCake)

        if i >= 0:
            ans += i + 1
        else:
            i = -i - 1
            ans += i

    return ans


# 算法调用
print(getResult())
